import { createActor, createMachine } from 'https://cdn.jsdelivr.net/npm/xstate@5/+esm';
const machine = createMachine(data.machine, data.implementations ?? {});
const actor = createActor(machine);
const trace = [];
actor.subscribe(s => trace.push({ value: s.value, context: s.context, status: s.status }));
actor.start();
for (const event of data.events ?? []) actor.send(event);
